def execute_tool(tool_name, parameters):
    try:
        tool = tool_registry.tools[tool_name]
        result = tool['function'](**parameters)
        return {
            "success": True,
            "result": result,
            "error": None
        }
    except Exception as e:
        return {
            "success": False, 
            "result": None,
            "error": str(e)
        }

