    Сформулируй финальный ответ на основе полученных данных.
    """
    return llm_generate(prompt)

# Модель генерирует цепочку: Мысль → Действие → Наблюдение
def react_loop(question):
    context = question
    for step in range(max_steps):
        # Генерация размышления и действия
        response = llm_generate(f"""
        Вопрос: {question}
        Контекст: {context}

        Мысль: [анализ ситуации]
        Действие: [вызов инструмента с параметрами]
        """)

        thought, action = parse_react_response(response)

        if action:
            result = execute_tool(action.tool, action.params)
            context += f"\nРезультат: {result}"
        else:
            # Генерация финального ответа
            return llm_generate(f"Итоговый ответ: {context}")

